"use strict";var parse=require("../"),test=require("tape");test("short -k=v",function(e){e.plan(1);var a=parse(["-b=123"]);e.deepEqual(a,{b:123,_:[]})}),test("multi short -k=v",function(e){e.plan(1);var a=parse(["-a=whatever","-b=robots"]);e.deepEqual(a,{a:"whatever",b:"robots",_:[]})}),test("short with embedded equals -k=a=b",function(e){e.plan(1);var a=parse(["-k=a=b"]);e.deepEqual(a,{k:"a=b",_:[]})}),test("short with later equals like -ab=c",function(e){e.plan(1);var a=parse(["-ab=c"]);e.deepEqual(a,{a:!0,b:"c",_:[]})});